  ('disabled-57f41407-moex-00286', 'disabled-57f41407', 'disabled-57f41407-moex-113-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '關於成年人之監護，下列何者正確？', '["監護人於監護關係存續中，若欲與受監護人結婚，須經法院許可", "監護人依法定順序決定之，若受監護人有配偶時，應由配偶擔任監護人", "監護之職務，包括受監護人之生活，因此監護人須親自照顧受監護人之 生活起居，包括洗澡、餵食等", "受監護人若於受監護宣告前，與第三人已訂有意定監護契約者，則法院 為監護宣告時，原則上以該第三人為其監護人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
