  ('disabled-57f41407-moex-00291', 'disabled-57f41407', 'disabled-57f41407-moex-113-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '刑事訴訟法所稱之限制書，究何所指？', '["限制辯護人與羈押之被告接見或互通書信，而由檢察官簽發之令狀", "限制被告處分扣押不動產之令狀", "限制辯護人與羈押之被告接見或互通書信，而由法官核發之令狀", "限制每一被告選任辯護人，不得逾3人之令狀"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
